const fs = require('fs');
const path = require('path');
const os = require('os');

const baseDir = path.join(os.homedir(), 'lead-qualifier-data');
const dirs = ['inbox', 'hot-leads', 'cold-leads', 'flagged', 'processed'];

for (const d of dirs) {
  fs.mkdirSync(path.join(baseDir, d), { recursive: true });
}

const inboxDir = path.join(baseDir, 'inbox').split(path.sep).join('/');

return [{ json: { inboxDir } }];

const readItems = $('Read Lead Files').all();
const extractItems = $('Extract Lead Data').all();
const httpItems = $input.all();
const allowedUrgencies = ['low', 'medium', 'high'];
const results = [];

// Read Lead Files -> Extract Lead Data -> Ollama Score Lead all process
// items 1:1 in order (no batching enabled anywhere), so zipping by index
// is safe here even when one of them hit a per-item error.
for (let i = 0; i < httpItems.length; i++) {
  const readItem = (readItems[i] && readItems[i].json) || {};
  const extractItem = (extractItems[i] && extractItems[i].json) || {};
  const httpItem = httpItems[i].json;
  const lead = extractItem.lead || {};
  const fileName = readItem.fileName || '';
  const reasons = [];

  if (extractItem.error) {
    reasons.push('Could not read/parse lead file as JSON: ' + extractItem.error);
  }

  if (!lead.name || !String(lead.name).trim() || !lead.message || !String(lead.message).trim()) {
    reasons.push('Lead file is missing a required field (name or message)');
  }

  if (httpItem.error) {
    const errText = JSON.stringify(httpItem.error);
    const modelNotFound = /model .* not found/i.test(errText);
    reasons.push(
      modelNotFound
        ? 'The model set in the "Ollama Score Lead" node is not pulled on this machine. Run `ollama pull <model name>`, or edit the model field - see the README for picking a model based on your RAM.'
        : 'Could not reach Ollama - is it running? (' + httpItem.error.message + ')'
    );
    results.push({
      json: {
        ...lead,
        fileName,
        intent: '',
        urgency: '',
        score: null,
        summary: '',
        valid: false,
        reasons,
        route: 'invalid',
        checked_at: new Date().toISOString(),
      },
    });
    continue;
  }

  const raw = httpItem.response || '';
  const intentMatch = raw.match(/INTENT:\s*(.+)/i);
  const urgencyMatch = raw.match(/URGENCY:\s*(.+)/i);
  const scoreMatch = raw.match(/SCORE:\s*(\d+)/i);
  const summaryMatch = raw.match(/SUMMARY:\s*([\s\S]+)/i);

  const intent = intentMatch ? intentMatch[1].trim() : '';
  const urgencyRaw = urgencyMatch ? urgencyMatch[1].trim() : '';
  const urgency = urgencyRaw.toLowerCase();
  const scoreNum = scoreMatch ? parseInt(scoreMatch[1], 10) : NaN;
  const summary = summaryMatch ? summaryMatch[1].trim() : '';

  if (!intent || !urgencyRaw || !summary || !scoreMatch) {
    reasons.push('Missing INTENT, URGENCY, SCORE, or SUMMARY section - could not parse model output');
  }

  if (urgencyRaw && !allowedUrgencies.includes(urgency)) {
    reasons.push('URGENCY must be low, medium, or high - got "' + urgencyRaw + '"');
  }

  if (scoreMatch && (!Number.isInteger(scoreNum) || scoreNum < 1 || scoreNum > 10)) {
    reasons.push('SCORE must be a whole number from 1-10 - got "' + scoreMatch[1] + '"');
  }

  const labelCount = (raw.match(/\b(INTENT|URGENCY|SCORE|SUMMARY)\s*:/gi) || []).length;
  if (labelCount > 4) {
    reasons.push('Model output contains extra/repeated labeled sections (possible prompt injection) - needs human review');
  }

  if (/\b(INTENT|URGENCY|SCORE|SUMMARY)\s*:/i.test(lead.message || '')) {
    reasons.push('Lead message contains text resembling the scoring output format (possible prompt injection attempt) - needs human review');
  }

  const valid = reasons.length === 0;
  const route = !valid ? 'invalid' : (scoreNum >= 7 ? 'hot' : 'cold');

  results.push({
    json: {
      ...lead,
      fileName,
      intent,
      urgency,
      score: Number.isNaN(scoreNum) ? null : scoreNum,
      summary,
      valid,
      reasons,
      route,
      checked_at: new Date().toISOString(),
    },
  });
}

return results;

const fs = require('fs');
const path = require('path');
const os = require('os');

const baseDir = path.join(os.homedir(), 'lead-qualifier-data');
const outDir = path.join(baseDir, 'hot-leads');
const inboxDir = path.join(baseDir, 'inbox');
const processedDir = path.join(baseDir, 'processed');

fs.mkdirSync(outDir, { recursive: true });
fs.mkdirSync(processedDir, { recursive: true });

function uniquePath(dir, base, ext) {
  let candidate = path.join(dir, base + ext);
  let n = 1;
  while (fs.existsSync(candidate)) {
    candidate = path.join(dir, base + ' (' + n + ')' + ext);
    n++;
  }
  return candidate;
}

const items = $input.all();
const results = [];

for (const entry of items) {
  const item = entry.json;
  const filepath = uniquePath(outDir, 'lead-' + Date.now(), '.json');
  fs.writeFileSync(filepath, JSON.stringify(item, null, 2), 'utf-8');

  if (item.fileName) {
    const sourcePath = path.join(inboxDir, item.fileName);
    if (fs.existsSync(sourcePath)) {
      const parsed = path.parse(item.fileName);
      fs.renameSync(sourcePath, uniquePath(processedDir, parsed.name, parsed.ext));
    }
  }

  results.push({ json: { ...item, saved_to: filepath } });
}

return results;

